"use client"

import { ViolinChart } from "@/components/ui/charts"

// Generate sample data
const generateData = (mean: number, std: number, n: number, seed: number) => {
  const values: number[] = []
  let s = seed
  for (let i = 0; i < n; i++) {
    s = (s * 9301 + 49297) % 233280
    const u1 = s / 233280
    s = (s * 9301 + 49297) % 233280
    const u2 = s / 233280
    const z = Math.sqrt(-2 * Math.log(u1 || 0.001)) * Math.cos(2 * Math.PI * u2)
    values.push(mean + std * z)
  }
  return values
}

// Before/After treatment comparison across different groups
const splitData = [
  {
    category: "Group A",
    groupA: { name: "Before", values: generateData(45, 12, 60, 10), color: "#94a3b8" },
    groupB: { name: "After", values: generateData(72, 10, 60, 11), color: "#3b82f6" },
  },
  {
    category: "Group B",
    groupA: { name: "Before", values: generateData(50, 15, 60, 20), color: "#94a3b8" },
    groupB: { name: "After", values: generateData(68, 12, 60, 21), color: "#3b82f6" },
  },
  {
    category: "Group C",
    groupA: { name: "Before", values: generateData(42, 10, 60, 30), color: "#94a3b8" },
    groupB: { name: "After", values: generateData(78, 8, 60, 31), color: "#3b82f6" },
  },
]

export default function ViolinChartSplit() {
  return (
    <ViolinChart
      variant="split"
      splitData={splitData}
      showBoxPlot
      showMedian
    />
  )
}
